UPDATE words SET example_en_2 = 'She prefers a light dinner so she sleeps better.', example_ko_2 = '그녀는 더 잘 자기 위해 저녁을 가볍게 먹어요.', example_en_3 = 'He cooked a special dinner for their anniversary.', example_ko_3 = '그는 기념일을 위해 특별한 저녁 식사를 요리했어요.', example_en_4 = 'What time do you usually have dinner?', example_ko_4 = '보통 몇 시에 저녁을 드세요?', example_en_5 = 'Dinner with the whole family is a great time to catch up.', example_ko_5 = '온 가족이 함께하는 저녁 식사는 서로의 이야기를 나누기 좋은 시간이에요.' WHERE id = 'w_cooking_A2_20';

